import numpy as np
import random

def algo(initial_population, individual_upper, individual_lower, objective_function):
    max_evaluations = 30000
    evaluations = 0
    best_solution = None
    best_fitness = float('inf')

    current_population = initial_population.copy()

    while evaluations < max_evaluations:
        fitness_values = np.array([objective_function(ind) for ind in current_population])
        evaluations += len(current_population)

        if best_solution is None or np.min(fitness_values) < best_fitness:
            best_fitness = np.min(fitness_values)
            best_solution = current_population[np.argmin(fitness_values)]

        neighborhood_size = np.clip(1.0 / (1 + np.exp(1 - best_fitness)), 0.01, 0.1)
        new_population = []

        for individual in current_population:
            perturbation = np.random.uniform(-neighborhood_size, neighborhood_size, size=individual.shape)
            offspring = np.clip(individual + perturbation, individual_lower, individual_upper)
            offspring_fitness = objective_function(offspring)

            if offspring_fitness < fitness_values[np.argwhere((current_population == individual).all(axis=1)).flatten()[0]]:
                new_population.append(offspring)
            else:
                acceptance_prob = np.exp((fitness_values[np.argwhere((current_population == individual).all(axis=1)).flatten()[0]] - offspring_fitness) / (1 + evaluations / max_evaluations))
                if random.random() < acceptance_prob:
                    new_population.append(offspring)
                else:
                    new_population.append(individual)

        if np.array_equal(new_population, current_population):
            current_population = np.random.uniform(individual_lower, individual_upper, size=current_population.shape)
        else:
            current_population = np.array(new_population)

    return best_solution

import numpy as np

def algo(initial_population, individual_upper, individual_lower, objective_function):
    population = initial_population
    max_evaluations = 30000
    evaluations = 0
    best_solution = None
    best_fitness = float('inf')

    while evaluations < max_evaluations:
        fitness_values = np.array([objective_function(ind) for ind in population])
        evaluations += len(population)

        if best_solution is None or np.min(fitness_values) < best_fitness:
            best_fitness = np.min(fitness_values)
            best_solution = population[np.argmin(fitness_values)]

        clusters = {}
        for i, fitness in enumerate(fitness_values):
            if fitness not in clusters:
                clusters[fitness] = []
            clusters[fitness].append(population[i])

        new_population = []
        for cluster in clusters.values():
            centroid = np.mean(cluster, axis=0)
            for _ in range(len(cluster)):
                random_walk = centroid + np.random.uniform(-0.1, 0.1, size=centroid.shape)
                random_walk = np.clip(random_walk, individual_lower, individual_upper)
                new_population.append(random_walk)

        population = np.array(new_population)
        if evaluations + len(population) > max_evaluations:
            population = population[:max_evaluations - evaluations]

    return best_solution
